import random


# ── Board ─────────────────────────────────────────────────────────────────────

def make_board():
    return [" "] * 9


def display_board(board):
    r = board
    print(f"\n {r[0]} │ {r[1]} │ {r[2]}")
    print("───┼───┼───")
    print(f" {r[3]} │ {r[4]} │ {r[5]}")
    print("───┼───┼───")
    print(f" {r[6]} │ {r[7]} │ {r[8]}\n")


WIN_LINES = [
    (0, 1, 2), (3, 4, 5), (6, 7, 8),   # rows
    (0, 3, 6), (1, 4, 7), (2, 5, 8),   # cols
    (0, 4, 8), (2, 4, 6),              # diagonals
]


def winner(board):
    for a, b, c in WIN_LINES:
        if board[a] != " " and board[a] == board[b] == board[c]:
            return board[a]
    return None


def is_full(board):
    return " " not in board


def available(board):
    return [i for i, v in enumerate(board) if v == " "]


# ── Minimax AI ────────────────────────────────────────────────────────────────

def minimax(board, is_maximizing):
    w = winner(board)
    if w == "O":
        return 1
    if w == "X":
        return -1
    if is_full(board):
        return 0

    if is_maximizing:
        best = -2
        for i in available(board):
            board[i] = "O"
            best = max(best, minimax(board, False))
            board[i] = " "
        return best
    else:
        best = 2
        for i in available(board):
            board[i] = "X"
            best = min(best, minimax(board, True))
            board[i] = " "
        return best


def computer_move(board):
    moves = available(board)

    # On the first move pick randomly for variety
    if len(moves) == 9:
        return random.choice(moves)

    best_score, best_move = -2, moves[0]
    for i in moves:
        board[i] = "O"
        score = minimax(board, False)
        board[i] = " "
        if score > best_score:
            best_score, best_move = score, i
    return best_move


# ── Human input ───────────────────────────────────────────────────────────────

def human_move(board):
    while True:
        try:
            raw = input("Your move (1-9): ").strip()
            idx = int(raw) - 1
            if idx not in range(9):
                raise ValueError
            if board[idx] != " ":
                print("That square is taken — try again.")
                continue
            return idx
        except ValueError:
            print("Enter a number from 1 to 9.")


# ── Game loop ─────────────────────────────────────────────────────────────────

def print_legend():
    print("Squares are numbered 1-9, left-to-right, top-to-bottom:")
    print("\n 1 │ 2 │ 3")
    print("───┼───┼───")
    print(" 4 │ 5 │ 6")
    print("───┼───┼───")
    print(" 7 │ 8 │ 9\n")


def play():
    print("\n=== Tic-Tac-Toe ===")
    print("You are X  •  Computer is O")
    print_legend()

    board = make_board()
    turn = "X"          # human goes first

    while True:
        display_board(board)

        if turn == "X":
            idx = human_move(board)
        else:
            print("Computer is thinking…")
            idx = computer_move(board)
            print(f"Computer plays square {idx + 1}.")

        board[idx] = turn
        w = winner(board)

        if w:
            display_board(board)
            if w == "X":
                print("You win! 🎉")
            else:
                print("Computer wins. Better luck next time!")
            break

        if is_full(board):
            display_board(board)
            print("It's a draw!")
            break

        turn = "O" if turn == "X" else "X"


def main():
    while True:
        play()
        again = input("\nPlay again? (y/n): ").strip().lower()
        if again != "y":
            print("Thanks for playing!")
            break


if __name__ == "__main__":
    main()

